import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const baseDir = path.resolve(__dirname, '..'); // Points to app/frontend/

async function validateFoundation() {
    console.log('Starting Natural Nation frontend foundation validation...');
    let success = true;
    const errors = [];

    const requiredFiles = [
        'index.html',
        'styles.css',
        'app.js',
        'README.md',
        'tests/validate-foundation.mjs' // The test script itself must exist
    ];

    const fileContents = {};

    // 1. Check for file existence and read content
    for (const file of requiredFiles) {
        const filePath = path.join(baseDir, file);
        try {
            fileContents[file] = await fs.readFile(filePath, 'utf8');
            console.log(`✓ Found file: ${file}`);
        } catch (error) {
            success = false;
            errors.push(`✖ Missing required file: ${file}`);
            console.error(`✖ Error: ${error.message}`);
        }
    }

    if (!success) {
        console.error('\nValidation failed due to missing files.');
        errors.forEach(err => console.error(err));
        process.exit(1);
    }

    // 2. Validate index.html content
    console.log('\nValidating index.html content...');
    const htmlContent = fileContents['index.html'];
    const htmlChecks = [
        { regex: /Natural Nation - Day 1 Dashboard/i, message: 'Presence of "Day 1 Dashboard" title' },
        { regex: /Duey/i, message: 'Mention of "Duey"' },
        { regex: /AI wellness mentor/i, message: 'Identification of Duey as "AI wellness mentor"' },
        { regex: /Wellness Score/i, message: 'Presence of "Wellness Score"' },
        { regex: /Rejuvenation Score/i, message: 'Presence of "Rejuvenation Score"' },
        { regex: /Daily Protocol Timeline/i, message: 'Presence of "Daily Protocol Timeline"' },
        { regex: /Check In/i, message: 'Presence of "Check In" controls' },
        { regex: /non-medical/i, message: 'Use of "non-medical" language' },
        { regex: /viewport/i, message: 'Viewport meta tag for responsiveness' },
        { regex: /<link[^>]+href=["']styles.css["']/i, message: 'Link to styles.css' },
        { regex: /<script[^>]+src=["']app.js["']/i, message: 'Link to app.js' }
    ];

    for (const check of htmlChecks) {
        if (!htmlContent.match(check.regex)) {
            success = false;
            errors.push(`✖ index.html: Failed - ${check.message}`);
            console.error(`✖ Failed: ${check.message}`);
        } else {
            console.log(`✓ Passed: ${check.message}`);
        }
    }

